import { 神將身, 武拳, 執植臂, 叉腰臂 } from './shinsho.js';
export const 珊底羅 = (bi) => 神將身(bi, {
    臂(bi, 筆) {
        const { M, L, C, Qk, S, 衣, 細 } = 筆;
        // 矛：長杆植岩，窄鋒承珠
        衣(() => {
            M(-15.9, 96.6);
            L(-15.9, 6.4);
            S();
            M(-16.8, 96.6);
            L(-16.8, 6.4);
            S();
            M(-15.9, 96.6);
            Qk(-16.35, 97.3, -16.8, 96.6);
            S(); // 石突
            bi.A(-16.35, 5.85, 0.52); // 承珠
            // 窄鋒：細長之刺
            M(-16.35, 5.3);
            C(-15.85, 4.2, -15.85, 0.8, -16.35, -3.3);
            S();
            M(-16.35, 5.3);
            C(-16.85, 4.2, -16.85, 0.8, -16.35, -3.3);
            S();
            細(() => { M(-16.35, 4.4); L(-16.35, -2.2); S(); });
        });
        // 右臂探杆（蔽內建），拳握之；左叉腰
        const { 拳 } = 執植臂(bi, 筆, -1);
        武拳(bi, 筆, 拳[0], 拳[1], { 轉: -Math.PI / 2 });
        叉腰臂(bi, 筆, 1);
    },
    冠識(bi, 筆) {
        // 午冠小識：長面之馬——面郭・雙耳・額鬃
        const { M, L, C, S, 細 } = 筆;
        細(() => bi.dim(0.8, () => {
            M(-0.45, 7.8);
            C(-0.5, 8.6, -0.3, 9.2, 0, 9.35);
            S();
            M(0.45, 7.8);
            C(0.5, 8.6, 0.3, 9.2, 0, 9.35);
            S();
            M(-0.45, 7.8);
            L(-0.7, 7.15);
            S();
            M(0.45, 7.8);
            L(0.7, 7.15);
            S();
            M(0, 7.7);
            L(0, 7.05);
            S();
        }));
    },
});
